library(haven); library(dplyr); library(readr); wave2 <- read_delim("data/input/wave_two_lsype_young_person_2020.tab", delim="\t", show_col_types=FALSE); wave4 <- read_delim("data/input/wave_four_lsype_young_person_2020.tab", delim="\t", show_col_types=FALSE); wave8_sc <- read_delim("data/input/ns8_2015_self_completion.tab", delim="\t", show_col_types=FALSE); wave8_derived <- read_delim("data/input/ns8_2015_derived.tab", delim="\t", show_col_types=FALSE); wave9_main <- read_delim("data/input/ns9_2022_main_interview.tab", delim="\t", show_col_types=FALSE); wave9_derived <- read_delim("data/input/ns9_2022_derived_variables.tab", delim="\t", show_col_types=FALSE); w2 <- wave2 %>% select(NSID, W2concenYP, W2nosleepYP, W2usefulYP, W2decideYP, W2strainYP, W2difficYP, W2activYP, W2probsYP, W2depressYP, W2noconfYP, W2wthlessYP, W2happyYP, W2ghq12scr); w4 <- wave4 %>% select(NSID, W4ConcenYP, W4NoSleepYP, W4UsefulYP, W4DecideYP, W4StrainYP, W4DifficYP, W4ActivYP, W4ProbsYP, W4DepressYP, W4NoConfYP, W4WthlessYP, W4HappyYP, W4ghq12scr); w8i <- wave8_sc %>% select(NSID, W8GHQ12_1, W8GHQ12_2, W8GHQ12_3, W8GHQ12_4, W8GHQ12_5, W8GHQ12_6, W8GHQ12_7, W8GHQ12_8, W8GHQ12_9, W8GHQ12_10, W8GHQ12_11, W8GHQ12_12); w8d <- wave8_derived %>% select(NSID, W8DGHQSC); w9i <- wave9_main %>% select(NSID, W9GHQ12_1, W9GHQ12_2, W9GHQ12_3, W9GHQ12_4, W9GHQ12_5, W9GHQ12_6, W9GHQ12_7, W9GHQ12_8, W9GHQ12_9, W9GHQ12_10, W9GHQ12_11, W9GHQ12_12); w9d <- wave9_derived %>% select(NSID, W9DGHQSC); dat <- full_join(w2, w4, by="NSID") %>% full_join(w8i, by="NSID") %>% full_join(w8d, by="NSID") %>% full_join(w9i, by="NSID") %>% full_join(w9d, by="NSID"); dat <- dat %>% mutate(ghq15=case_when(W2ghq12scr %in% c(-96,-99) ~ -3, W2ghq12scr %in% c(-97,-92) ~ -9, is.na(W2ghq12scr) ~ -3, TRUE~as.numeric(W2ghq12scr)), ghq17=case_when(W4ghq12scr %in% c(-96,-99) ~ -3, W4ghq12scr %in% c(-97,-92) ~ -9, is.na(W4ghq12scr) ~ -3, TRUE~as.numeric(W4ghq12scr)), ghq25=case_when(is.na(W8DGHQSC) ~ -3, TRUE~as.numeric(W8DGHQSC)), ghq32=case_when(is.na(W9DGHQSC) ~ -3, TRUE~as.numeric(W9DGHQSC))); ghqtl_fn <- function(m) { all_na <- apply(m,1,function(x) all(is.na(x))); any_neg <- apply(m,1,function(x) any(x<0,na.rm=TRUE)); s <- rowSums(m,na.rm=TRUE); ifelse(all_na,-3,ifelse(any_neg,-8,s)) }; dat$ghqtl15 <- ghqtl_fn(as.matrix(dat %>% select(W2concenYP,W2nosleepYP,W2usefulYP,W2decideYP,W2strainYP,W2difficYP,W2activYP,W2probsYP,W2depressYP,W2noconfYP,W2wthlessYP,W2happyYP))); dat$ghqtl17 <- ghqtl_fn(as.matrix(dat %>% select(W4ConcenYP,W4NoSleepYP,W4UsefulYP,W4DecideYP,W4StrainYP,W4DifficYP,W4ActivYP,W4ProbsYP,W4DepressYP,W4NoConfYP,W4WthlessYP,W4HappyYP))); dat$ghqtl25 <- ghqtl_fn(as.matrix(dat %>% select(W8GHQ12_1,W8GHQ12_2,W8GHQ12_3,W8GHQ12_4,W8GHQ12_5,W8GHQ12_6,W8GHQ12_7,W8GHQ12_8,W8GHQ12_9,W8GHQ12_10,W8GHQ12_11,W8GHQ12_12))); dat$ghqtl32 <- ghqtl_fn(as.matrix(dat %>% select(W9GHQ12_1,W9GHQ12_2,W9GHQ12_3,W9GHQ12_4,W9GHQ12_5,W9GHQ12_6,W9GHQ12_7,W9GHQ12_8,W9GHQ12_9,W9GHQ12_10,W9GHQ12_11,W9GHQ12_12))); out <- dat %>% select(NSID,ghq15,ghq17,ghq25,ghq32,ghqtl15,ghqtl17,ghqtl25,ghqtl32) %>% mutate(across(-NSID, as.factor)); dir.create("data/output",showWarnings=FALSE,recursive=TRUE); write_csv(out,"data/output/cleaned_data.csv"); cat("Done\n")